import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import com.google.gson.GsonBuilder;
import java.lang.reflect.Field;

public class GsonBuilderTest {

  @Test
  public void testSetPrettyPrinting() throws Exception {
    GsonBuilder builder = new GsonBuilder();

    // Initially prettyPrinting should be false or default value
    Field prettyPrintingField = GsonBuilder.class.getDeclaredField("prettyPrinting");
    prettyPrintingField.setAccessible(true);
    boolean before = prettyPrintingField.getBoolean(builder);
    assertFalse(before, "prettyPrinting should be false by default");

    // Invoke setPrettyPrinting
    GsonBuilder returned = builder.setPrettyPrinting();

    // Verify method returns the same instance
    assertSame(builder, returned, "setPrettyPrinting should return the same GsonBuilder instance");

    // Verify prettyPrinting field is set to true
    boolean after = prettyPrintingField.getBoolean(builder);
    assertTrue(after, "prettyPrinting should be true after calling setPrettyPrinting");
  }
}
